import React, { useEffect, useState } from 'react';
import axios from 'axios';
import './FarmListPage.css'; // Đảm bảo bạn có file CSS này để styling
import { useNavigate } from 'react-router-dom'; // Import useNavigate cho điều hướng

function FarmListPage() { // Hoặc RegisterManageSub2Page nếu bạn đã đổi tên component
  const [farms, setFarms] = useState([]); // Đảm bảo farms luôn được khởi tạo là một mảng rỗng
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [searchTerm, setSearchTerm] = useState(''); // State cho ô tìm kiếm
  const [selectedFarmType, setSelectedFarmType] = useState('all'); // State cho bộ lọc loại hình

  const navigate = useNavigate(); // Khởi tạo hook useNavigate

  useEffect(() => {
    const fetchFarms = async () => {
      setLoading(true);
      setError(null); // Reset lỗi
      try {
        const token = localStorage.getItem('token');
        if (!token) {
          setError('Bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
          setLoading(false);
          setFarms([]); // Đảm bảo farms là mảng rỗng
          navigate('/login'); // Chuyển hướng đến trang đăng nhập nếu không có token
          return;
        }

        // Tạo tham số query cho API
        const params = {};
        if (selectedFarmType !== 'all') {
          params.farmType = selectedFarmType;
        }

        const response = await axios.get('http://localhost:10000/api/farms', {
          headers: {
            Authorization: `Bearer ${token}`
          },
          params: params
        });

        // Cập nhật logic xử lý dữ liệu từ backend để mạnh mẽ hơn và thêm log
        console.log('API Raw Response Data:', response.data); // LOG: Xem toàn bộ response.data
        console.log('Type of API Response Data:', typeof response.data); // LOG: Xem kiểu dữ liệu của response.data

        let receivedFarms = [];
        if (response.data) {
          if (Array.isArray(response.data)) {
            console.log('Response data is directly an array.');
            receivedFarms = response.data;
          } else if (typeof response.data === 'object' && response.data.data && Array.isArray(response.data.data)) {
            console.log('Response data has a "data" property which is an array.');
            receivedFarms = response.data.data;
          } else {
            console.error('Response data is not an array and does not contain an array in .data property. Received:', response.data);
            setError('Dữ liệu danh sách cơ sở nhận được từ server không đúng định dạng. Vui lòng kiểm tra API backend.');
          }
        } else {
          console.error('No data received from server. Response:', response);
          setError('Không nhận được dữ liệu từ server.');
        }
        setFarms(receivedFarms); // Cập nhật state farms

      } catch (err) {
        console.error('❌ Lỗi khi lấy danh sách farms:', err.response?.data || err.message);
        if (err.response && err.response.status === 401) {
          setError('Phiên đăng nhập đã hết hạn hoặc bạn chưa đăng nhập. Vui lòng đăng nhập lại.');
          localStorage.removeItem('token'); // Xóa token hết hạn
          navigate('/login'); // Chuyển hướng đến trang đăng nhập
        } else {
          setError('Không thể tải danh sách cơ sở. Vui lòng thử lại.');
        }
        setFarms([]); // Đảm bảo farms là một mảng rỗng khi có lỗi
      } finally {
        setLoading(false);
      }
    };

    fetchFarms();
  }, [selectedFarmType, navigate]);

  console.log('Current farms state before filter:', farms);

  const filteredFarms = Array.isArray(farms) ? farms.filter(farm => {
    const matchesSearchTerm = searchTerm === '' ||
                              (farm.tenCoSo && farm.tenCoSo.toLowerCase().includes(searchTerm.toLowerCase())) ||
                              (farm.diaChiCoSo && farm.diaChiCoSo.toLowerCase().includes(searchTerm.toLowerCase())) || // Đã sửa từ diaChi
                              (farm.tenNguoiDaiDien && farm.tenNguoiDaiDien.toLowerCase().includes(searchTerm.toLowerCase())) || // Đã sửa từ tenChuCoSo
                              (farm.soDienThoaiNguoiDaiDien && farm.soDienThoaiNguoiDaiDien.includes(searchTerm)); // Đã sửa từ soDienThoai

    const matchesFarmType = selectedFarmType === 'all' ||
                            (farm.loaiCoSoDangKy && farm.loaiCoSoDangKy === selectedFarmType);

    return matchesSearchTerm && matchesFarmType;
  }) : [];

  if (loading) {
    return <div className="farm-list-container">Đang tải danh sách cơ sở...</div>;
  }

  if (error) {
    return <div className="farm-list-container error-message">Lỗi: {error}</div>;
  }

  return (
    <div className="farm-list-container">
      <h2>📋 Danh sách cơ sở</h2>

      <div className="filter-controls">
        <input
          type="text"
          placeholder="Tìm kiếm theo tên, địa chỉ, người đại diện, SĐT..." // Cập nhật placeholder
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="search-input"
        />
        <select
          value={selectedFarmType}
          onChange={(e) => setSelectedFarmType(e.target.value)}
          className="type-filter-select"
        >
          <option value="all">Tất cả loại hình</option>
          <option value="Đăng ký cơ sở gây nuôi">Cơ sở gây nuôi</option>
          <option value="Đăng ký cơ sở kinh doanh, chế biến gỗ">Cơ sở kinh doanh, chế biến gỗ</option>
        </select>
      </div>

      {filteredFarms.length === 0 ? (
        <p className="no-data-message">Không tìm thấy cơ sở nào phù hợp với tiêu chí tìm kiếm/lọc.</p>
      ) : (
        <div className="table-responsive">
          <table className="farm-table">
            <thead>
              <tr>
                <th>Tên cơ sở</th>
                <th>Địa chỉ</th> {/* Đây là Địa chỉ cơ sở */}
                <th>Tỉnh/Thành phố</th>
                <th>Xã/Phường</th>
                <th>Người đại diện</th>
                <th>Số điện thoại</th>
                <th>Loại hình đăng ký</th>
                {/* Thêm các cột khác nếu cần */}
              </tr>
            </thead>
            <tbody>
              {filteredFarms.map((f) => (
                <tr key={f._id}>
                  <td>{f.tenCoSo}</td>
                  <td>{f.diaChiCoSo}</td> {/* Đã sửa từ f.diaChi */}
                  <td>{f.tinhThanhPho}</td>
                  <td>{f.xaPhuong}</td>
                  <td>{f.tenNguoiDaiDien}</td> {/* Đã sửa từ f.tenChuCoSo */}
                  <td>{f.soDienThoaiNguoiDaiDien}</td> {/* Đã sửa từ f.soDienThoai */}
                  <td>{f.loaiCoSoDangKy || 'N/A'}</td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

export default FarmListPage;
